package com.careeros.search.domain; import com.careeros.common.domain.AuditableEntity; import jakarta.persistence.*; import org.hibernate.annotations.UuidGenerator; import java.util.*;
@Entity @Table(name="saved_searches") public class SavedSearch extends AuditableEntity{@Id @UuidGenerator private UUID id;@Column(nullable=false)private String name;private String title;private String sorting;private Integer minimumScore;private Boolean remote;@ElementCollection(fetch=FetchType.EAGER)@CollectionTable(name="saved_search_companies",joinColumns=@JoinColumn(name="saved_search_id"))private List<UUID> companies=new ArrayList<>();@ElementCollection(fetch=FetchType.EAGER)@CollectionTable(name="saved_search_locations",joinColumns=@JoinColumn(name="saved_search_id"))private List<String> locations=new ArrayList<>();@ElementCollection(fetch=FetchType.EAGER)@CollectionTable(name="saved_search_technologies",joinColumns=@JoinColumn(name="saved_search_id"))private List<String> technologies=new ArrayList<>();protected SavedSearch(){}public static SavedSearch create(String n,String t,String sort,Integer min,Boolean remote,List<UUID>c,List<String>l,List<String>tech){var s=new SavedSearch();s.change(n,t,sort,min,remote,c,l,tech);return s;}public void change(String n,String t,String sort,Integer min,Boolean remote,List<UUID>c,List<String>l,List<String>tech){if(n==null||n.isBlank())throw new IllegalArgumentException("name is required");if(min!=null&&(min<0||min>100))throw new IllegalArgumentException("minimumScore must be 0..100");name=n;title=t;sorting=sort;minimumScore=min;this.remote=remote;companies=new ArrayList<>(c==null?List.of():c);locations=new ArrayList<>(l==null?List.of():l);technologies=new ArrayList<>(tech==null?List.of():tech);}public UUID getId(){return id;}public String getName(){return name;}public String getTitle(){return title;}public String getSorting(){return sorting;}public Integer getMinimumScore(){return minimumScore;}public Boolean getRemote(){return remote;}public List<UUID>getCompanies(){return List.copyOf(companies);}public List<String>getLocations(){return List.copyOf(locations);}public List<String>getTechnologies(){return List.copyOf(technologies);}}
